  ('bookkeeper-moex-01261', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行所得稅法之規定，下列敘述何者正確？ 財產出租收有押金者，應按當地銀行業通行之一年期存款利率，計算租賃收入 出租房屋之成本、費用無法核計者，以其租金收入之57%為必要成本 參加競技比賽所獲得之獎金，減除必要費用後按20%分離課稅 按月領取之勞保給付按15%分離課稅', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
